  <style>
      @font-face {
        font-family: "NVIDIA Sans";
        src: url("https://images.nvidia.com/etc/designs/nvidiaGDC/clientlibs_base/fonts/nvidia-sans/NALA/var/NVIDIASansVF_NALA_W_Wght.woff2") format("woff2");
        font-weight: 100 900;
        font-style: normal;
        font-display: swap;
      }

      /* ==========================================================
         RESET & BASE
         ========================================================== */
      *,
      *::before,
      *::after {
        box-sizing: border-box;
        margin: 0;
        padding: 0;
      }

      /* ==========================================================
         FAB BUTTON (bottom-right trigger)
         ========================================================== */
      #fab-button {
        position: fixed !important;
        bottom: 24px !important;
        right: 24px !important;
        display: flex;
        align-items: center;
        gap: 10px;
        background: #1a1a1a;
        border-radius: 8px;
        padding: 12px 22px;
        border: none;
        color: #fff;
        font-size: 14px;
        font-weight: 600;
        font-family: inherit;
        cursor: pointer;
        box-shadow: 0 0 12px rgba(180, 150, 100, 0.3),
                    0 0 24px rgba(180, 150, 100, 0.12);
        z-index: 10000 !important;
        overflow: visible;
        transition: transform 0.2s, box-shadow 0.2s, opacity 0.3s ease,
          visibility 0.3s ease;
      }

      #fab-button:hover {
        transform: scale(1.05);
        box-shadow: 0 0 16px rgba(180, 150, 100, 0.45),
                    0 0 32px rgba(180, 150, 100, 0.2);
      }

      #fab-button svg {
        width: 20px;
        height: 20px;
        fill: currentColor;
        flex-shrink: 0;
      }

      #fab-button.bc-hidden {
        opacity: 0 !important;
        visibility: hidden !important;
        pointer-events: none;
      }

      /* Gold gradient border for FAB and Close buttons */
      #fab-button::before,
      #close-button::before {
        content: "";
        position: absolute;
        inset: -2px;
        padding: 2px;
        border-radius: 10px;
        background: conic-gradient(
          from var(--angle, 0deg),
          #8b7355 0%, #6d5a3a 5%, #7a6542 10%, #d4c4a8 15%, #b8956e 20%,
          #c9a86c 25%, #e8dcc4 30%, #f5ede0 35%, #c4a064 40%, #8b7355 45%,
          #7a6542 50%, #b89b6a 55%, #d4c4a8 60%, #e8dcc4 65%, #c9a86c 70%,
          #b8956e 75%, #a68b5b 80%, #8b7355 85%, #6d5a3a 90%, #9a8262 95%,
          #8b7355 100%
        );
        -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
        -webkit-mask-composite: xor;
        mask-composite: exclude;
        pointer-events: none;
        z-index: -1;
        animation: rotateGradientBorder 20s linear infinite;
      }

      @media (prefers-reduced-motion: reduce) {
        #fab-button::before,
        #close-button::before {
          animation: none;
        }
      }

      /* ==========================================================
         MODAL BACKDROP
         ========================================================== */
      #modal-backdrop {
        position: fixed !important;
        top: 0 !important;
        left: 0 !important;
        width: 100vw !important;
        height: 100vh !important;
        background: rgba(0, 0, 0, 0.8) !important;
        z-index: 10100 !important;
        display: none !important;
        opacity: 0;
        transition: opacity 0.3s ease;
      }

      #modal-backdrop.bc-visible {
        display: block !important;
        opacity: 1;
      }

      /* ==========================================================
         CHAT MODAL
         ========================================================== */
      #chat-modal {
        position: fixed !important;
        top: 45% !important;
        left: 50% !important;
        transform: translate(-50%, -50%);
        width: 85vw;
        max-width: 1050px;
        height: 85vh;
        max-height: 800px;
        border-radius: 16px;
        display: none;
        flex-direction: column;
        overflow: hidden;
        box-shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
        z-index: 10200 !important;
        background: rgba(0, 0, 0, 0.9);
      }

      #chat-modal.bc-visible {
        display: flex !important;
      }

      /* Modal adapts background based on state */
      #chat-modal.state-welcome {
        background: rgba(0, 0, 0, 0.9);
      }

      #chat-modal.state-chat {
        background: rgba(0, 0, 0, 0.9);
      }

      /* Modal body */
      #chat-modal .bc-modal-body {
        flex: 1;
        overflow: hidden;
        position: relative;
      }

      /* ==========================================================
         CLOSE BUTTON (external, bottom-right of page)
         ========================================================== */
      #close-button {
        position: fixed !important;
        bottom: calc((100vh - min(75vh, 900px)) / 2 - 60px) !important;
        right: calc((100vw - min(75vw, 1050px)) / 2) !important;
        display: none;
        align-items: center;
        gap: 8px;
        background: #1a1a1a;
        border-radius: 8px;
        padding: 12px 22px;
        border: none;
        color: #fff;
        font-size: 14px;
        font-weight: 600;
        font-family: inherit;
        cursor: pointer;
        box-shadow: 0 0 12px rgba(180, 150, 100, 0.3),
                    0 0 24px rgba(180, 150, 100, 0.12);
        z-index: 10300 !important;
        overflow: visible;
        transition: transform 0.2s, box-shadow 0.2s;
      }

      #close-button.bc-visible {
        display: flex !important;
      }

      #close-button:hover {
        transform: scale(1.05);
        box-shadow: 0 0 16px rgba(180, 150, 100, 0.45),
                    0 0 32px rgba(180, 150, 100, 0.2);
      }

      #close-button svg {
        flex-shrink: 0;
      }

      /* ==========================================================
         WELCOME CONTENT (custom entry point, dark theme)
         ========================================================== */
      #welcome-content {
        width: 100%;
        height: 100%;
        background: transparent;
        color: #ffffff;
        display: flex;
        flex-direction: column;
        overflow-y: auto;
      }

      #welcome-content.bc-hidden {
        display: none !important;
      }

     .welcome__description , .welcome__privacy, .welcome__consent{
 padding-top: 0;
  padding-bottom: 0;
}

      .welcome__body {
        flex: 1;
        padding: 24px 16px 16px;
        overflow-y: auto;
      }

      /* Two-column response layout (avatar column + content column) */
      .welcome__response {
        display: flex;
        gap: 16px;
      }

      .welcome__avatar-col {
        display: flex;
        flex-direction: column;
        gap: 4px;
        align-items: center;
        flex-shrink: 0;
      }

      .welcome__avatar-icon {
        width: 24px;
        height: 25px;
        flex-shrink: 0;
      }

      .welcome__avatar-icon svg {
        width: 24px;
        height: 25px;
        fill: #fff;
      }

      .welcome__avatar-line {
        width: 2px;
        flex: 1;
        background: #76b900;
      }

      .welcome__content-col {
        display: flex;
        flex-direction: column;
        gap: 30px;
        flex: 1;
        min-width: 0;
      }

      .welcome__title-text {
        font-size: 24px;
        font-weight: 500;
        line-height: 1.2;
        letter-spacing: -0.25px;
        color: #eeeeee;
      }

      .welcome__description {
        font-size: 16px;
        line-height: 1.5;
        color: #eeeeee;
      }

      .welcome__privacy {
        font-size: 16px;
        line-height: 1.5;
        color: #eeeeee;
        margin-bottom: 12px;
      }

      .welcome__privacy a {
        color: #eeeeee;
        text-decoration: underline;
        text-decoration-color: #8fcb2b;
        text-underline-offset: 2px;
        text-decoration-skip-ink: none;
      }

      .welcome__privacy a:hover {
        color: #eeeeee;
      }

      .welcome__consent {
        font-size: 16px;
        line-height: 1.5;
        color: #eeeeee;
        font-weight: 700;
      }

      .welcome__consent a {
        color: #eeeeee;
        text-decoration: underline;
        text-decoration-color: #8fcb2b;
        text-underline-offset: 2px;
        text-decoration-skip-ink: none;
      }

      .welcome__consent a:hover {
        color: #eeeeee;
      }

      /* Suggestion cards section */
      .welcome__cards-heading {
        font-size: 16px;
        font-weight: 700;
        color: #ffffff;
      }

      .welcome__cards {
        display: grid;
        grid-template-columns: repeat(3, 1fr);
        gap: 20px;
        margin-bottom: 0;
      }

      .welcome__card {
        background: #292929;
        border: 1px solid #5e5e5e;
        border-radius: 4px;
        padding: 16px;
        cursor: pointer;
        transition: background 0.2s, border-color 0.2s, transform 0.15s;
      }

      .welcome__card:hover {
        background: #333;
        border-color: #555;
        transform: translateY(-2px);
      }

      .welcome__card:focus-visible {
        outline: 2px solid #76b900;
        outline-offset: 2px;
      }

      .welcome__card-icon {
        width: 16px;
        height: 16px;
        margin-bottom: 12px;
        opacity: 1;
      }

      .welcome__card-icon svg {
        width: 16px;
        height: 16px;
        fill: #f2f2f2;
      }

      .welcome__card-title {
        font-size: 16px;
        font-weight: 500;
        line-height: 1.2;
        letter-spacing: -0.25px;
        color: #f2f2f2;
        margin-bottom: 8px;
      }

      .welcome__card-text {
        font-size: 14px;
        color: #f2f2f2;
        line-height: 1.5;
      }

      /* Input section (pinned at bottom of welcome) */
      .welcome__input-section {
        padding: 16px;
        background: transparent;
        flex-shrink: 0;
      }

      .welcome__input-wrap {
        display: flex;
        flex-direction: column;
        background: #161616;
        border: 1px solid transparent;
        border-radius: 8px;
        padding: 0;
        transition: border-color 0.2s;
        height: 117px;
        position: relative;
        box-shadow: 0px 0px 4px 0px rgba(0,0,0,0.17), 0px 6px 18px 2px rgba(0,0,0,0.17);
        overflow: hidden;
        cursor: text;
      }

      .welcome__input-wrap:hover,
      .welcome__input-wrap:focus-within {
        border: 1px solid #76b900;
      }

      .welcome__prompt-area {
        padding: 16px;
        flex: 1;
        display: flex;
        align-items: flex-start;
      }

      .welcome__action-bar {
        height: 61px;
        padding: 8px;
        display: flex;
        justify-content: space-between;
        align-items: center;
        background: transparent;
      }

      .welcome__action-items {
        display: flex;
        align-items: center;
      }

      .welcome__input {
        width: 100%;
        height: 100%;
        border: none;
        outline: none;
        background: transparent;
        font-size: 15px;
        color: #ffffff;
        font-family: inherit;
        resize: none;
        line-height: 1.667;
      }

      .welcome__input::placeholder {
        color: #a7a7a7;
      }

      .welcome__send {
        width: 40px;
        height: 40px;
        border-radius: 4px;
        border: none;
        background: #76b900;
        color: #fff;
        cursor: pointer;
        display: flex;
        align-items: center;
        justify-content: center;
        flex-shrink: 0;
        transition: background 0.2s, transform 0.1s;
      }

      .welcome__send:hover {
        background: #8ad400;
        transform: scale(1.05);
      }

      .welcome__send:disabled {
        background: #444;
        color: #777;
        cursor: default;
        transform: none;
      }

      .welcome__send svg {
        width: 16px;
        height: 16px;
        fill: currentColor;
      }

      .welcome__disclaimer {
        text-align: center;
        font-size: 11px;
        color: #eeeeee;
        padding: 8px 16px 16px;
        background: transparent;
        flex-shrink: 0;
      }

      /* ==========================================================
         BRAND CONCIERGE MOUNT
         ========================================================== */
      #brand-concierge-mount {
        width: 100%;
        height: 100%;
      }

      #brand-concierge-mount.bc-hidden {
        display: none !important;
      }

      /* ==========================================================
         MOBILE RESPONSIVE
         ========================================================== */
      @media (max-width: 768px) {
        #chat-modal {
          width: 100vw !important;
          height: 100vh !important;
          border-radius: 0;
          top: 0 !important;
